     1→/**
     2→ * PM Slice
     3→ *
     4→ * State management for PM schedules, drag-drop interactions, and constraints.
     5→ * Handles real-time validation during drag operations.
     6→ *
     7→ * @see specs/006-user-interface.md Section 6.4
     8→ */
     9→
    10→import { createSlice, createAsyncSlice } from '@belt/tools';
    11→import type {
    12→  PmScheduleEntry,
    13→  PmType,
    14→  DragState,
    15→  ConstraintViolation,
    16→  PmStatus,
    17→} from '../types';
    18→
    19→// =============================================================================
    20→// PM Slice State
    21→// =============================================================================
    22→
    23→interface UndoEntry {
    24→  pmId: string;
    25→  previousDate: string;
    26→  newDate: string;
    27→  timestamp: number;
    28→}
    29→
    30→interface PendingMove {
    31→  targetDate: string;
    32→  originalDate: string;
    33→}
    34→
    35→export interface PmSliceState {
    36→  pmSchedule: PmScheduleEntry[];
    37→  pmTypes: PmType[];
    38→  drag: DragState;
    39→  lockedPmIds: Record<string, boolean>;
    40→  editingPmId: string | null;
    41→  pendingMoves: Record<string, PendingMove>;
    42→  constraintCache: Record<string, ConstraintViolation[]>;
    43→  lastValidation: number | null;
    44→  undoStack: UndoEntry[];
    45→  maxUndoDepth: number;
    46→  [key: string]: unknown;
    47→}
    48→
    49→const initialPmState: PmSliceState = {
    50→  pmSchedule: [],
    51→  pmTypes: [],
    52→  drag: {
    53→    isDragging: false,
    54→    pmId: null,
    55→    sourceDate: null,
    56→    targetDate: null,
    57→    isValid: true,
    58→    validationMessage: null,
    59→    constraintViolations: [],
    60→  },
    61→  lockedPmIds: {},
    62→  editingPmId: null,
    63→  pendingMoves: {},
    64→  constraintCache: {},
    65→  lastValidation: null,
    66→  undoStack: [],
    67→  maxUndoDepth: 50,
    68→};
    69→
    70→export const pmSlice = createSlice({
    71→  id: 'pm',
    72→  initial: initialPmState,
    73→  cache: { policy: 'session' },
    74→  reducers: {
    75→    // PM Schedule Operations
    76→    setPmSchedule: (s, schedule: PmScheduleEntry[]) => {
    77→      const state = s as PmSliceState;
    78→      state.pmSchedule = schedule;
    79→    },
    80→
    81→    setPmTypes: (s, types: PmType[]) => {
    82→      const state = s as PmSliceState;
    83→      state.pmTypes = types;
    84→    },
    85→
    86→    updatePm: (s, pm: Partial<PmScheduleEntry> & { id: string }) => {
    87→      const state = s as PmSliceState;
    88→      const index = state.pmSchedule.findIndex((p) => p.id === pm.id);
    89→      if (index !== -1) {
    90→        state.pmSchedule[index] = { ...state.pmSchedule[index], ...pm };
    91→      }
    92→    },
    93→
    94→    addPm: (s, pm: PmScheduleEntry) => {
    95→      const state = s as PmSliceState;
    96→      state.pmSchedule.push(pm);
    97→    },
    98→
    99→    removePm: (s, pmId: string) => {
   100→      const state = s as PmSliceState;
   101→      state.pmSchedule = state.pmSchedule.filter((p) => p.id !== pmId);
   102→    },
   103→
   104→    updatePmStatus: (s, payload: { pmId: string; status: PmStatus }) => {
   105→      const state = s as PmSliceState;
   106→      const pm = state.pmSchedule.find((p) => p.id === payload.pmId);
   107→      if (pm) {
   108→        pm.status = payload.status;
   109→      }
   110→    },
   111→
   112→    // Drag and Drop
   113→    startDrag: (s, payload: { pmId: string; sourceDate: string }) => {
   114→      const state = s as PmSliceState;
   115→      if (state.lockedPmIds[payload.pmId]) {
   116→        return;
   117→      }
   118→
   119→      state.drag = {
   120→        isDragging: true,
   121→        pmId: payload.pmId,
   122→        sourceDate: payload.sourceDate,
   123→        targetDate: payload.sourceDate,
   124→        isValid: true,
   125→        validationMessage: null,
   126→        constraintViolations: [],
   127→      };
   128→    },
   129→
   130→    updateDragTarget: (s, targetDate: string) => {
   131→      const state = s as PmSliceState;
   132→      if (!state.drag.isDragging) return;
   133→
   134→      state.drag.targetDate = targetDate;
   135→
   136→      const cacheKey = `${state.drag.pmId}:${targetDate}`;
   137→      const cachedViolations = state.constraintCache[cacheKey];
