   142→        state.drag.validationMessage =
   143→          cachedViolations.length > 0
   144→            ? cachedViolations.map((v) => v.message).join('; ')
   145→            : null;
   146→      }
   147→    },
   148→
   149→    setDragValidation: (
   150→      s,
   151→      payload: {
   152→        isValid: boolean;
   153→        message: string | null;
   154→        violations: ConstraintViolation[];
   155→      }
   156→    ) => {
   157→      const state = s as PmSliceState;
   158→      state.drag.isValid = payload.isValid;
   159→      state.drag.validationMessage = payload.message;
   160→      state.drag.constraintViolations = payload.violations;
   161→
   162→      if (state.drag.pmId && state.drag.targetDate) {
   163→        const cacheKey = `${state.drag.pmId}:${state.drag.targetDate}`;
   164→        state.constraintCache[cacheKey] = payload.violations;
   165→      }
   166→      state.lastValidation = Date.now();
   167→    },
   168→
   169→    endDrag: (s, commit: boolean) => {
   170→      const state = s as PmSliceState;
   171→      if (!state.drag.isDragging || !state.drag.pmId) {
   172→        state.drag = {
   173→          isDragging: false,
   174→          pmId: null,
   175→          sourceDate: null,
   176→          targetDate: null,
   177→          isValid: true,
   178→          validationMessage: null,
   179→          constraintViolations: [],
   180→        };
   181→        return;
   182→      }
   183→
   184→      if (commit && state.drag.isValid && state.drag.targetDate !== state.drag.sourceDate) {
   185→        const pm = state.pmSchedule.find((p) => p.id === state.drag.pmId);
   186→        if (pm) {
