   343→// =============================================================================
   344→// Async PM Slice
   345→// =============================================================================
   346→
   347→export interface PmApiResponse {
   348→  schedule: PmScheduleEntry[];
   349→  types: PmType[];
   350→}
   351→
   352→export const pmAsyncSlice = createAsyncSlice({
   353→  id: 'pmApi',
   354→  cache: {
   355→    policy: 'public',
   356→    ttl: '2m',
   357→    swr: true,
   358→  },
   359→  context: {
   360→    baseUrl: '/api/v1',
   361→    startDate: new Date().toISOString().split('T')[0],
   362→    endDate: new Date(Date.now() + 84 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
   363→  },
   364→  load: async (ctx) => {
   365→    const { baseUrl, startDate, endDate } = ctx as {
   366→      baseUrl: string;
   367→      startDate: string;
   368→      endDate: string;
