/**
 * MMS Infinite Canvas
 *
 * The main canvas component that renders PM schedule data at different zoom levels.
 * Uses deck.gl for strategic view (WebGL) and Konva for tactical/operational views (Canvas 2D).
 *
 * Zoom Level Rendering:
 * - STRATEGIC (0-4): deck.gl WebGL heatmap
 * - TACTICAL_WIDE (4-8): deck.gl WebGL compressed blocks
 * - TACTICAL (8-12): Konva HTML5 Canvas Gantt
 * - OPERATIONAL (12-16): Konva HTML5 Canvas detailed cards
 * - DETAIL (16+): React DOM overlay
 *
 * Based on specs/006-user-interface.md Section 6.3.
 */

import { useRef } from 'react';
import { Card, NonIdealState, Spinner, Tag, Button, ButtonGroup } from '@blueprintjs/core';

import { useCanvas, useCanvasData, useFleet, loadStrategicData, loadTacticalData, loadTacticalWideData, loadOperationalData, loadDetailData } from '../../store';
import type { CanvasSliceState } from '../../store/slices/canvas';
import type { CanvasDataState } from '../../store/slices/canvas';
import type { FleetSliceState } from '../../store/slices/fleet';
import { StrategicHeatmapLayer, TacticalWideLayer, TacticalGanttLayer, OperationalDetailLayer, DetailCardOverlay, type HeatmapCell, type PmBlock, type OperationalPmBlock } from './layers';

/** Default canvas dimensions when container size is not available */
const DEFAULT_CANVAS_WIDTH = 1200;
const DEFAULT_CANVAS_HEIGHT = 800;

export function InfiniteCanvas() {
  const { state: canvasStateRaw, actions: canvasActions } = useCanvas();
  const { state: canvasDataStateRaw, actions: canvasDataActions } = useCanvasData();
  const { state: fleetStateRaw } = useFleet();

  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
  const canvasDataState = canvasDataStateRaw as unknown as CanvasDataState;
  const fleetState = fleetStateRaw as unknown as FleetSliceState;

  const { zoom, zoomLevel, viewport, isPanning, layers } = canvasState;
  const {
    strategicData, strategicLoading, strategicError, fromYear, toYear,
    tacticalWideData, tacticalWideLoading, tacticalWideError, tacticalWideFromDate, tacticalWideToDate,
    tacticalData, tacticalLoading, tacticalError, tacticalFromDate, tacticalToDate,
    operationalData, operationalLoading, operationalError, operationalFromDate, operationalToDate,
    detailData, detailLoading, detailError, detailFromDate, detailToDate, detailExpandedPmIds
  } = canvasDataState;
  const isLoading = fleetState.trains.length === 0;

  const tooltipPosRef = useRef<{ x: number; y: number }>({ x: 0, y: 0 });
  const tooltipRef = useRef<HTMLDivElement>(null);

  const handleWheel = (event: React.WheelEvent) => {
    event.preventDefault();
    const delta = event.deltaY > 0 ? -0.5 : 0.5;
    const newZoom = Math.max(0, Math.min(20, zoom + delta));
    canvasActions.setZoom(newZoom);
  };

  const handleMouseDown = (event: React.MouseEvent) => {
    if (event.button === 0) {
      canvasActions.startPanning();
    }
  };

  const handleMouseUp = () => {
    canvasActions.stopPanning();
  };

  const handleMouseMove = (event: React.MouseEvent) => {
    if (isPanning) {
      canvasActions.pan({
        dx: -event.movementX,
        dy: -event.movementY,
      });
    }
    tooltipPosRef.current = { x: event.clientX, y: event.clientY };
  };

  const handleLoadStrategicData = () => {
    loadStrategicData(canvasDataActions, {
      fromYear,
      toYear,
    });
  };

  const handleLoadTacticalWideData = () => {
    loadTacticalWideData(canvasDataActions, {
      fromDate: tacticalWideFromDate,
      toDate: tacticalWideToDate,
    });
  };

  const handleLoadTacticalData = () => {
    loadTacticalData(canvasDataActions, {
      fromWeek: tacticalFromDate,
      toWeek: tacticalToDate,
    });
  };

  const handleLoadOperationalData = () => {
    loadOperationalData(canvasDataActions, {
      fromDate: operationalFromDate,
      toDate: operationalToDate,
    });
  };

  const handleLoadDetailData = () => {
    loadDetailData(canvasDataActions, {
      fromDate: detailFromDate,
      toDate: detailToDate,
    });
  };

  const handleDetailPmSelect = (pmId: string) => {
    canvasActions.selectPm(pmId);
  };

  const handleDetailPmExpand = (pmId: string) => {
    canvasDataActions.expandDetailPm(pmId);
  };

  const handleDetailPmCollapse = (pmId: string) => {
    canvasDataActions.collapseDetailPm(pmId);
  };

  const handleDetailPmEdit = (pmId: string, field: string) => {
    // In production, this would dispatch an edit action to the PM service
    console.log(`Edit PM ${pmId} field ${field}`);
  };

  const handleDetailPmLock = (pmId: string) => {
    // In production, this would dispatch a lock action
    console.log(`Lock PM ${pmId}`);
  };

  const handleDetailPmUnlock = (pmId: string) => {
    // In production, this would dispatch an unlock action
    console.log(`Unlock PM ${pmId}`);
  };

  const handleDetailViewHistory = (pmId: string) => {
    // In production, this would open a history panel
    console.log(`View history for PM ${pmId}`);
  };

  const handlePmBlockHover = (pm: PmBlock | null) => {
    if (tooltipRef.current) {
      if (pm) {
        tooltipRef.current.style.display = 'block';
        tooltipRef.current.style.left = `${tooltipPosRef.current.x + 10}px`;
        tooltipRef.current.style.top = `${tooltipPosRef.current.y + 10}px`;
        tooltipRef.current.innerHTML = `
          <div style="font-weight: 600; margin-bottom: 4px;">
            ${pm.pmCode} - ${pm.trainNumber}
          </div>
          <div style="color: #64748b;">
            <div>Date: <strong>${pm.targetDate}</strong></div>
            <div>Duration: <strong>${pm.durationDays} day${pm.durationDays > 1 ? 's' : ''}</strong></div>
            <div>Status: <strong>${pm.status}</strong></div>
            ${pm.depotCode ? `<div>Depot: <strong>${pm.depotCode}</strong></div>` : ''}
            ${pm.trackNumber ? `<div>Track: <strong>${pm.trackNumber}</strong></div>` : ''}
            ${pm.estimatedHours ? `<div>Hours: <strong>${pm.estimatedHours}h</strong></div>` : ''}
            ${pm.isLocked ? '<div style="color: #d97706;">🔒 Locked</div>' : ''}
          </div>
        `;
      } else {
        tooltipRef.current.style.display = 'none';
      }
    }
  };

  const handlePmBlockClick = (pmId: string) => {
    canvasActions.selectPm(pmId);
  };

  // Tactical-Wide block handlers
  const handleTacticalWideBlockHover = (block: { pmId: string; trainNumber: string; pmCode: string; targetDate: string; status: string; durationWeeks: number; isLocked: boolean } | null) => {
    if (tooltipRef.current) {
      if (block) {
        tooltipRef.current.style.display = 'block';
        tooltipRef.current.style.left = `${tooltipPosRef.current.x + 10}px`;
        tooltipRef.current.style.top = `${tooltipPosRef.current.y + 10}px`;
        tooltipRef.current.innerHTML = `
          <div style="font-weight: 600; margin-bottom: 4px;">
            ${block.pmCode} - ${block.trainNumber}
          </div>
          <div style="color: #64748b;">
            <div>Date: <strong>${block.targetDate}</strong></div>
            <div>Status: <strong>${block.status}</strong></div>
            <div>Duration: <strong>~${block.durationWeeks} week(s)</strong></div>
            ${block.isLocked ? '<div style="color: #d97706;">🔒 Locked</div>' : ''}
          </div>
        `;
      } else {
        tooltipRef.current.style.display = 'none';
      }
    }
  };

  const handleTacticalWideBlockClick = (block: { pmId: string }) => {
    canvasActions.selectPm(block.pmId);
  };

  const handleMonthClick = (month: number, year: number) => {
    // Zoom into tactical view for the clicked month
    canvasActions.setZoom(10); // Move to TACTICAL zoom level
    const startDate = new Date(year, month, 1);
    const endDate = new Date(year, month + 3, 0); // 3 months view
    canvasActions.setViewport({
      startDate: startDate.toISOString().split('T')[0],
      endDate: endDate.toISOString().split('T')[0],
    });
  };

  const handleCellHover = (cell: HeatmapCell | null) => {
    if (tooltipRef.current) {
      if (cell) {
        tooltipRef.current.style.display = 'block';
        tooltipRef.current.style.left = `${tooltipPosRef.current.x + 10}px`;
        tooltipRef.current.style.top = `${tooltipPosRef.current.y + 10}px`;
        tooltipRef.current.innerHTML = `
          <div style="font-weight: 600; margin-bottom: 4px;">
            Train ${cell.trainNumber} - ${cell.year}
          </div>
          <div style="color: #64748b;">
            <div>PM Count: <strong>${cell.pmCount}</strong></div>
            <div>Total Hours: <strong>${cell.totalHours.toFixed(1)}h</strong></div>
            ${cell.completedCount > 0 ? `<div>Completed: <strong>${cell.completedCount}</strong></div>` : ''}
            ${cell.lockedCount > 0 ? `<div>Locked: <strong>${cell.lockedCount}</strong></div>` : ''}
          </div>
        `;
      } else {
        tooltipRef.current.style.display = 'none';
      }
    }
  };

  const handleCellClick = (cell: HeatmapCell) => {
    canvasActions.setZoom(6);
    canvasActions.setViewport({
      startDate: `${cell.year}-01-01`,
      endDate: `${cell.year}-12-31`,
      trainIds: [cell.trainId],
    });
  };

  const handleYearClick = (year: number) => {
    canvasActions.setZoom(6);
    canvasActions.setViewport({
      startDate: `${year}-01-01`,
      endDate: `${year}-12-31`,
    });
  };

  const handleOperationalPmHover = (pm: OperationalPmBlock | null) => {
    if (tooltipRef.current) {
      if (pm) {
        tooltipRef.current.style.display = 'block';
        tooltipRef.current.style.left = `${tooltipPosRef.current.x + 10}px`;
        tooltipRef.current.style.top = `${tooltipPosRef.current.y + 10}px`;
        const materialInfo = pm.materials.length > 0
          ? pm.materials.map(m => `${m.status === 'AVAILABLE' ? '✓' : '⚠'} ${m.materialName}`).slice(0, 3).join('<br/>')
          : '<span style="color: #94a3b8; font-style: italic;">No materials required</span>';
        tooltipRef.current.innerHTML = `
          <div style="font-weight: 600; margin-bottom: 8px;">
            ${pm.pmCode} - ${pm.trainNumber}
          </div>
          <div style="color: #64748b;">
            <div><strong>${pm.pmDescription}</strong></div>
            <div style="margin-top: 4px;">Date: <strong>${pm.targetDate} - ${pm.endDate}</strong></div>
            <div>Duration: <strong>${pm.durationDays} day${pm.durationDays > 1 ? 's' : ''}</strong></div>
            <div>Status: <strong>${pm.status}</strong></div>
            ${pm.depotCode ? `<div>Depot: <strong>${pm.depotCode}</strong></div>` : ''}
            ${pm.trackNumber ? `<div>Track: <strong>${pm.trackNumber}</strong></div>` : ''}
            ${pm.estimatedHours ? `<div>Hours: <strong>${pm.estimatedHours}h</strong></div>` : ''}
            ${pm.assignedShift ? `<div>Shift: <strong>${pm.assignedShift}</strong></div>` : ''}
            ${pm.isLocked ? '<div style="color: #d97706; margin-top: 4px;">🔒 Locked in Maximo</div>' : ''}
            <div style="margin-top: 8px; border-top: 1px solid #e2e8f0; padding-top: 8px;">
              <strong>Materials:</strong><br/>
              ${materialInfo}
            </div>
          </div>
        `;
      } else {
        tooltipRef.current.style.display = 'none';
      }
    }
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <NonIdealState
          icon={<Spinner size={48} />}
          title="Loading fleet data..."
          description="Fetching trains and PM schedule"
        />
      );
    }

    if (fleetState.trains.length === 0) {
      return (
        <NonIdealState
          icon="train"
          title="No trains found"
          description="No trains match the current filters"
        />
      );
    }

    if (zoomLevel === 'STRATEGIC') {
      if (strategicLoading) {
        return (
          <NonIdealState
            icon={<Spinner size={48} />}
            title="Loading strategic view..."
            description="Fetching PM density data"
          />
        );
      }

      if (strategicError) {
        return (
          <NonIdealState
            icon="error"
            title="Error loading strategic view"
            description={strategicError}
            action={
              <Button intent="primary" onClick={handleLoadStrategicData}>
                Retry
              </Button>
            }
          />
        );
      }

      if (!strategicData) {
        return (
          <NonIdealState
            icon="heat-grid"
            title="Strategic View"
            description="Load PM density heatmap for multi-year planning"
            action={
              <ButtonGroup>
                <Button intent="primary" onClick={handleLoadStrategicData}>
                  Load Strategic Data
                </Button>
              </ButtonGroup>
            }
          >
            <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
              <p>Shows 10-year PM density across {fleetState.trains.length} trains</p>
            </div>
          </NonIdealState>
        );
      }

      return (
        <>
          <StrategicHeatmapLayer
            data={strategicData}
            fromYear={fromYear}
            toYear={toYear}
            width="100%"
            height="100%"
            onCellHover={handleCellHover}
            onCellClick={handleCellClick}
            onYearClick={handleYearClick}
          />
          <div
            ref={tooltipRef}
            style={{
              display: 'none',
              position: 'fixed',
              backgroundColor: 'white',
              border: '1px solid #e2e8f0',
              borderRadius: '6px',
              padding: '8px 12px',
              boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
              pointerEvents: 'none',
              zIndex: 100,
              fontSize: '12px',
              lineHeight: 1.5,
            }}
          />
        </>
      );
    }

    if (zoomLevel === 'TACTICAL_WIDE') {
      if (tacticalWideLoading) {
        return (
          <NonIdealState
            icon={<Spinner size={48} />}
            title="Loading tactical-wide view..."
            description="Fetching yearly PM schedule data"
          />
        );
      }

      if (tacticalWideError) {
        return (
          <NonIdealState
            icon="error"
            title="Error loading tactical-wide view"
            description={tacticalWideError}
            action={
              <Button intent="primary" onClick={handleLoadTacticalWideData}>
                Retry
              </Button>
            }
          />
        );
      }

      if (!tacticalWideData) {
        return (
          <NonIdealState
            icon="calendar"
            title="Tactical Wide View"
            description="Load 1-year PM schedule with monthly granularity"
            action={
              <ButtonGroup>
                <Button intent="primary" onClick={handleLoadTacticalWideData}>
                  Load Tactical Wide Data
                </Button>
              </ButtonGroup>
            }
          >
            <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
              <p>Shows PM schedule from {tacticalWideFromDate} to {tacticalWideToDate}</p>
              <p>Monthly granularity with compressed Gantt blocks</p>
            </div>
          </NonIdealState>
        );
      }

      return (
        <>
          <TacticalWideLayer
            data={tacticalWideData}
            fromDate={new Date(tacticalWideFromDate)}
            toDate={new Date(tacticalWideToDate)}
            width="100%"
            height="100%"
            selectedPmIds={canvasState.selection.selectedPmIds}
            onBlockHover={handleTacticalWideBlockHover}
            onBlockClick={handleTacticalWideBlockClick}
            onMonthClick={handleMonthClick}
          />
          <div
            ref={tooltipRef}
            style={{
              display: 'none',
              position: 'fixed',
              backgroundColor: 'white',
              border: '1px solid #e2e8f0',
              borderRadius: '6px',
              padding: '8px 12px',
              boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
              pointerEvents: 'none',
              zIndex: 100,
              fontSize: '12px',
              lineHeight: 1.5,
            }}
          />
        </>
      );
    }

    if (zoomLevel === 'TACTICAL') {
      if (tacticalLoading) {
        return (
          <NonIdealState
            icon={<Spinner size={48} />}
            title="Loading tactical view..."
            description="Fetching PM schedule data"
          />
        );
      }

      if (tacticalError) {
        return (
          <NonIdealState
            icon="error"
            title="Error loading tactical view"
            description={tacticalError}
            action={
              <Button intent="primary" onClick={handleLoadTacticalData}>
                Retry
              </Button>
            }
          />
        );
      }

      if (!tacticalData) {
        return (
          <NonIdealState
            icon="gantt-chart"
            title="Tactical View"
            description="Load 12-week PM schedule Gantt chart"
            action={
              <ButtonGroup>
                <Button intent="primary" onClick={handleLoadTacticalData}>
                  Load Tactical Data
                </Button>
              </ButtonGroup>
            }
          >
            <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
              <p>Shows PM schedule from {tacticalFromDate} to {tacticalToDate}</p>
            </div>
          </NonIdealState>
        );
      }

      // Build train order from tactical data
      const trainIds = Array.from(new Set(tacticalData.pmBlocks.map(pm => pm.trainId)));
      const containerWidth = DEFAULT_CANVAS_WIDTH;
      const containerHeight = DEFAULT_CANVAS_HEIGHT;

      return (
        <>
          <TacticalGanttLayer
            data={tacticalData}
            trainOrder={trainIds}
            fromDate={new Date(tacticalFromDate)}
            toDate={new Date(tacticalToDate)}
            width={containerWidth}
            height={containerHeight}
            selectedPmIds={canvasState.selection.selectedPmIds}
            onPmClick={handlePmBlockClick}
            onPmHover={handlePmBlockHover}
            showConstraintWalls={layers.complianceWindows}
            showGrid={true}
          />
          <div
            ref={tooltipRef}
            style={{
              display: 'none',
              position: 'fixed',
              backgroundColor: 'white',
              border: '1px solid #e2e8f0',
              borderRadius: '6px',
              padding: '8px 12px',
              boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
              pointerEvents: 'none',
              zIndex: 100,
              fontSize: '12px',
              lineHeight: 1.5,
            }}
          />
        </>
      );
    }

    // OPERATIONAL and DETAIL zoom levels
    if (zoomLevel === 'OPERATIONAL') {
      if (operationalLoading) {
        return (
          <NonIdealState
            icon={<Spinner size={48} />}
            title="Loading operational view..."
            description="Fetching detailed PM schedule data"
          />
        );
      }

      if (operationalError) {
        return (
          <NonIdealState
            icon="error"
            title="Error loading operational view"
            description={operationalError}
            action={
              <Button intent="primary" onClick={handleLoadOperationalData}>
                Retry
              </Button>
            }
          />
        );
      }

      if (!operationalData) {
        return (
          <NonIdealState
            icon="id-number"
            title="Operational View"
            description="Load 4-week detailed PM cards with material status"
            action={
              <ButtonGroup>
                <Button intent="primary" onClick={handleLoadOperationalData}>
                  Load Operational Data
                </Button>
              </ButtonGroup>
            }
          >
            <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
              <p>Shows PM schedule from {operationalFromDate} to {operationalToDate}</p>
              <p>Daily granularity with detailed PM cards</p>
            </div>
          </NonIdealState>
        );
      }

      const containerWidth = DEFAULT_CANVAS_WIDTH;
      const containerHeight = DEFAULT_CANVAS_HEIGHT;

      return (
        <>
          <OperationalDetailLayer
            data={operationalData}
            fromDate={new Date(operationalFromDate)}
            toDate={new Date(operationalToDate)}
            width={containerWidth}
            height={containerHeight}
            selectedPmIds={canvasState.selection.selectedPmIds}
            onPmClick={handlePmBlockClick}
            onPmHover={handleOperationalPmHover}
            showGrid={true}
          />
          <div
            ref={tooltipRef}
            style={{
              display: 'none',
              position: 'fixed',
              backgroundColor: 'white',
              border: '1px solid #e2e8f0',
              borderRadius: '6px',
              padding: '12px 16px',
              boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
              pointerEvents: 'none',
              zIndex: 100,
              fontSize: '12px',
              lineHeight: 1.6,
              maxWidth: '350px',
            }}
          />
        </>
      );
    }

    // DETAIL view (zoom 16+) - React DOM overlay with full PM editing
    if (detailLoading) {
      return (
        <NonIdealState
          icon={<Spinner size={48} />}
          title="Loading detail view..."
          description="Fetching detailed PM data with history"
        />
      );
    }

    if (detailError) {
      return (
        <NonIdealState
          icon="error"
          title="Error loading detail view"
          description={detailError}
          action={
            <Button intent="primary" onClick={handleLoadDetailData}>
              Retry
            </Button>
          }
        />
      );
    }

    if (!detailData) {
      return (
        <NonIdealState
          icon="document"
          title="Detail View"
          description="Load 1-week PM schedule with full editing capabilities"
          action={
            <ButtonGroup>
              <Button intent="primary" onClick={handleLoadDetailData}>
                Load Detail Data
              </Button>
            </ButtonGroup>
          }
        >
          <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
            <p>Shows PM schedule from {detailFromDate} to {detailToDate}</p>
            <ul style={{ textAlign: 'left', maxWidth: '300px', margin: '8px auto' }}>
              <li>Full PM editing interface</li>
              <li>Constraint validation feedback</li>
              <li>Material availability status</li>
              <li>Change history timeline</li>
            </ul>
          </div>
        </NonIdealState>
      );
    }

    return (
      <DetailCardOverlay
        data={detailData}
        fromDate={new Date(detailFromDate)}
        toDate={new Date(detailToDate)}
        width={DEFAULT_CANVAS_WIDTH}
        height={DEFAULT_CANVAS_HEIGHT}
        selectedPmIds={canvasState.selection.selectedPmIds}
        expandedPmIds={detailExpandedPmIds}
        onPmSelect={handleDetailPmSelect}
        onPmExpand={handleDetailPmExpand}
        onPmCollapse={handleDetailPmCollapse}
        onPmEdit={handleDetailPmEdit}
        onPmLock={handleDetailPmLock}
        onPmUnlock={handleDetailPmUnlock}
        onViewHistory={handleDetailViewHistory}
      />
    );
  };

  return (
    <div
      className="mms-canvas"
      style={{
        flex: 1,
        position: 'relative',
        overflow: 'hidden',
        backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
        cursor: isPanning ? 'grabbing' : 'grab',
      }}
      onWheel={handleWheel}
      onMouseDown={handleMouseDown}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
      onMouseMove={handleMouseMove}
    >
      <div
        style={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          transform: `translate(${-canvasState.panX}px, ${-canvasState.panY}px)`,
          transition: isPanning ? 'none' : 'transform 0.1s ease-out',
        }}
      >
        {renderContent()}
      </div>

      <div style={{
        position: 'absolute',
        top: '12px',
        right: '12px',
        zIndex: 10,
      }}>
        <Card elevation={1} style={{ padding: '8px 12px' }}>
          <div style={{ fontSize: '11px', color: 'var(--pt-text-muted)', marginBottom: '4px' }}>
            Zoom Level
          </div>
          <div style={{ fontSize: '14px', fontWeight: 600 }}>
            {zoomLevel.replace('_', ' ')}
          </div>
          <div style={{ fontSize: '11px', fontFamily: 'monospace' }}>
            {zoom.toFixed(1)} / 20
          </div>
        </Card>
      </div>

      <div style={{
        position: 'absolute',
        bottom: '12px',
        left: '12px',
        zIndex: 10,
      }}>
        <Card elevation={1} style={{ padding: '8px 12px' }}>
          <div style={{ fontSize: '11px' }}>
            <span style={{ color: 'var(--pt-text-muted)' }}>Viewport: </span>
            <span style={{ fontFamily: 'monospace' }}>
              {viewport.startDate} to {viewport.endDate}
            </span>
          </div>
          <div style={{ fontSize: '11px' }}>
            <span style={{ color: 'var(--pt-text-muted)' }}>Trains: </span>
            <span>{viewport.trainIds.length || 'All'}</span>
          </div>
        </Card>
      </div>

      {(canvasState.layers.manhourOverlay || canvasState.layers.driftOverlay || canvasState.layers.baselineShadow) && (
        <div style={{
          position: 'absolute',
          top: '12px',
          left: '12px',
          zIndex: 10,
          display: 'flex',
          gap: '4px',
        }}>
          {canvasState.layers.manhourOverlay && (
            <Tag intent="primary" icon="chart">Man-hours</Tag>
          )}
          {canvasState.layers.driftOverlay && (
            <Tag intent="warning" icon="delta">Drift</Tag>
          )}
          {canvasState.layers.baselineShadow && (
            <Tag minimal icon="git-commit">Baseline</Tag>
          )}
        </div>
      )}
    </div>
  );
}

