        return (
          <NonIdealState
            icon="error"
            title="Error loading operational view"
            description={operationalError}
            action={
              <Button intent="primary" onClick={handleLoadOperationalData}>
                Retry
              </Button>
            }
          />
        );
      }

      if (!operationalData) {
        return (
          <NonIdealState
            icon="id-number"
            title="Operational View"
            description="Load 4-week detailed PM cards with material status"
            action={
              <ButtonGroup>
                <Button intent="primary" onClick={handleLoadOperationalData}>
                  Load Operational Data
                </Button>
              </ButtonGroup>
            }
          >
            <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
              <p>Shows PM schedule from {operationalFromDate} to {operationalToDate}</p>
              <p>Daily granularity with detailed PM cards</p>
            </div>
          </NonIdealState>
        );
      }

      const containerWidth = DEFAULT_CANVAS_WIDTH;
      const containerHeight = DEFAULT_CANVAS_HEIGHT;

      return (
        <>
          <OperationalDetailLayer
            data={operationalData}
            fromDate={new Date(operationalFromDate)}
            toDate={new Date(operationalToDate)}
            width={containerWidth}
            height={containerHeight}
            selectedPmIds={canvasState.selection.selectedPmIds}
            onPmClick={handlePmBlockClick}
            onPmHover={handleOperationalPmHover}
            showGrid={true}
          />
          <div
            ref={tooltipRef}
            style={{
              display: 'none',
              position: 'fixed',
              backgroundColor: 'white',
              border: '1px solid #e2e8f0',
              borderRadius: '6px',
              padding: '12px 16px',
              boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
              pointerEvents: 'none',
              zIndex: 100,
              fontSize: '12px',
              lineHeight: 1.6,
              maxWidth: '350px',
            }}
          />
        </>
      );
    }

    // DETAIL view (zoom 16+) - React DOM overlay with full PM editing
    if (detailLoading) {
      return (
        <NonIdealState
          icon={<Spinner size={48} />}
          title="Loading detail view..."
          description="Fetching detailed PM data with history"
        />
      );
    }

    if (detailError) {
      return (
        <NonIdealState
          icon="error"
          title="Error loading detail view"
          description={detailError}
          action={
            <Button intent="primary" onClick={handleLoadDetailData}>
              Retry
            </Button>
          }
        />
      );
    }

    if (!detailData) {
      return (
        <NonIdealState
          icon="document"
          title="Detail View"
          description="Load 1-week PM schedule with full editing capabilities"
          action={
            <ButtonGroup>
              <Button intent="primary" onClick={handleLoadDetailData}>
                Load Detail Data
              </Button>
            </ButtonGroup>
          }
        >
          <div style={{ marginTop: '16px', fontSize: '12px', color: 'var(--pt-text-muted)' }}>
            <p>Shows PM schedule from {detailFromDate} to {detailToDate}</p>
            <ul style={{ textAlign: 'left', maxWidth: '300px', margin: '8px auto' }}>
              <li>Full PM editing interface</li>
              <li>Constraint validation feedback</li>
              <li>Material availability status</li>
              <li>Change history timeline</li>
            </ul>
          </div>
        </NonIdealState>
      );
    }

    return (
      <DetailCardOverlay
        data={detailData}
        fromDate={new Date(detailFromDate)}
        toDate={new Date(detailToDate)}
        width={DEFAULT_CANVAS_WIDTH}
        height={DEFAULT_CANVAS_HEIGHT}
        selectedPmIds={canvasState.selection.selectedPmIds}
        expandedPmIds={detailExpandedPmIds}
        onPmSelect={handleDetailPmSelect}
        onPmExpand={handleDetailPmExpand}
        onPmCollapse={handleDetailPmCollapse}
        onPmEdit={handleDetailPmEdit}
        onPmLock={handleDetailPmLock}
        onPmUnlock={handleDetailPmUnlock}
        onViewHistory={handleDetailViewHistory}
      />
    );
  };

  return (
    <div
      className="mms-canvas"
      style={{
        flex: 1,
        position: 'relative',
        overflow: 'hidden',
        backgroundColor: 'var(--pt-app-background-color, #f5f8fa)',
        cursor: isPanning ? 'grabbing' : 'grab',
      }}
      onWheel={handleWheel}
      onMouseDown={handleMouseDown}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
      onMouseMove={handleMouseMove}
    >
      <div
        style={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          transform: `translate(${-canvasState.panX}px, ${-canvasState.panY}px)`,
          transition: isPanning ? 'none' : 'transform 0.1s ease-out',
        }}
      >
        {renderContent()}
      </div>

      <div style={{
        position: 'absolute',
        top: '12px',
        right: '12px',
        zIndex: 10,
      }}>
        <Card elevation={1} style={{ padding: '8px 12px' }}>
          <div style={{ fontSize: '11px', color: 'var(--pt-text-muted)', marginBottom: '4px' }}>
            Zoom Level
          </div>
          <div style={{ fontSize: '14px', fontWeight: 600 }}>
            {zoomLevel.replace('_', ' ')}
          </div>
          <div style={{ fontSize: '11px', fontFamily: 'monospace' }}>
            {zoom.toFixed(1)} / 20
          </div>
        </Card>
      </div>

      <div style={{
        position: 'absolute',
        bottom: '12px',
        left: '12px',
        zIndex: 10,
      }}>
        <Card elevation={1} style={{ padding: '8px 12px' }}>
          <div style={{ fontSize: '11px' }}>
            <span style={{ color: 'var(--pt-text-muted)' }}>Viewport: </span>
            <span style={{ fontFamily: 'monospace' }}>
              {viewport.startDate} to {viewport.endDate}
            </span>
          </div>
          <div style={{ fontSize: '11px' }}>
            <span style={{ color: 'var(--pt-text-muted)' }}>Trains: </span>
            <span>{viewport.trainIds.length || 'All'}</span>
          </div>
        </Card>
      </div>

      {(canvasState.layers.manhourOverlay || canvasState.layers.driftOverlay || canvasState.layers.baselineShadow) && (
        <div style={{
          position: 'absolute',
          top: '12px',
          left: '12px',
          zIndex: 10,
          display: 'flex',
          gap: '4px',
        }}>
          {canvasState.layers.manhourOverlay && (
            <Tag intent="primary" icon="chart">Man-hours</Tag>
          )}
          {canvasState.layers.driftOverlay && (
            <Tag intent="warning" icon="delta">Drift</Tag>
          )}
          {canvasState.layers.baselineShadow && (
            <Tag minimal icon="git-commit">Baseline</Tag>
          )}
        </div>
      )}

      {/* Drag Confirmation Dialog */}
      <DragConfirmationDialog
        isOpen={dragConfirmRef.current.isOpen}
        pmCode={dragConfirmRef.current.pmCode}
        trainNumber={dragConfirmRef.current.trainNumber}
        sourceDate={dragConfirmRef.current.sourceDate}
        targetDate={dragConfirmRef.current.targetDate}
        impact={dragConfirmRef.current.impact}
        violations={pmState.drag.constraintViolations}
        isLoading={dragConfirmRef.current.isLoadingImpact}
        onConfirm={handleDragConfirm}
        onCancel={handleDragCancel}
      />
    </div>
  );
}

